sql:
SELECT COUNT(pupil_id) 
FROM pupils 
WHERE school_id = 1 AND age < 10;

SELECT name, age
FROM pupils
WHERE age < 11;

SELECT COUNT(DISTINCT user_id) AS number_of_beacons_of_wisdom
FROM users
WHERE role = 'teacher';

external_knowledge:
